// Build stats query
return {
  json: {
    statsQuery: `
      SELECT
        (SELECT COUNT(*) FROM users WHERE status = 'active') as total_users,
        (SELECT COUNT(*) FROM users WHERE created_at::date = CURRENT_DATE) as new_users_today,
        (SELECT COUNT(*) FROM markets WHERE status = 'active') as active_markets,
        (SELECT COUNT(*) FROM markets WHERE status = 'resolved' AND resolved_at::date = CURRENT_DATE) as resolved_today,
        (SELECT COALESCE(SUM(volume), 0) FROM trading_volume WHERE recorded_at::date = CURRENT_DATE) as volume_today,
        (SELECT COUNT(*) FROM deposits WHERE status = 'pending') as pending_deposits,
        (SELECT COUNT(*) FROM withdrawals WHERE status = 'pending') as pending_withdrawals,
        (SELECT COALESCE(SUM(amount), 0) FROM deposits WHERE status = 'approved' AND created_at::date = CURRENT_DATE) as deposit_amount_today,
        (SELECT COALESCE(SUM(amount), 0) FROM withdrawals WHERE status = 'approved' AND created_at::date = CURRENT_DATE) as withdrawal_amount_today
    `
  }
};

// Extract stats
const response = $input.first().json;
const stats = Array.isArray(response) ? response[0] : response;

// Format numbers in Bengali style
const formatNum = (n) => {
  if (n >= 10000000) return (n / 10000000).toFixed(1) + ' Cr';
  if (n >= 100000) return (n / 100000).toFixed(1) + ' L';
  if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
  return n.toString();
};

const formatBDT = (n) => '৳' + formatNum(Math.round(n));

// Determine trend emoji
const volume = stats.volume_today || 0;
const volumeEmoji = volume > 100000 ? '📈' : volume > 10000 ? '📊' : '📉';

// Top categories query
return {
  json: {
    stats,
    total_users: stats.total_users || 0,
    new_users_today: stats.new_users_today || 0,
    active_markets: stats.active_markets || 0,
    resolved_today: stats.resolved_today || 0,
    volume_today: stats.volume_today || 0,
    pending_deposits: stats.pending_deposits || 0,
    pending_withdrawals: stats.pending_withdrawals || 0,
    deposit_amount_today: stats.deposit_amount_today || 0,
    withdrawal_amount_today: stats.withdrawal_amount_today || 0,
    formatNum,
    formatBDT,
    volumeEmoji,
    date: new Date().toLocaleDateString('bn-BD', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
};

// Format Bengali report
const data = $input.first().json;

const message = `
📊 <b>প্লোকিমার্কেট দৈনিক রিপোর্ট</b>

📅 <b>তারিখ:</b> ${data.date}

👥 <b>ব্যবহারকারী</b>
• মোট ব্যবহারকারী: ${data.total_users.toLocaleString('bn-BD')}
• আজ নতুন: ${data.new_users_today.toLocaleString('bn-BD')}

📈 <b>মার্কেট</b>
• সক্রিয় মার্কেট: ${data.active_markets.toLocaleString('bn-BD')}
• আজ সমাধান: ${data.resolved_today.toLocaleString('bn-BD')}

💰 <b>ভলিউম ও ট্রেডিং</b>
${data.volumeEmoji} আজকের ভলিউম: ${data.formatBDT(data.volume_today)}

🏦 <b>ডিপোজিট ও উইথড্র</b>
• আজকের ডিপোজিট: ${data.formatBDT(data.deposit_amount_today)}
• আজকের উইথড্র: ${data.formatBDT(data.withdrawal_amount_today)}
• পেন্ডিং ডিপোজিট: ${data.pending_deposits}টি
• পেন্ডিং উইথড্র: ${data.pending_withdrawals}টি

🔗 <a href="https://polymarket-bangladesh.vercel.app/admin">অ্যাডমিন প্যানেল</a>
`.trim();

return {
  json: {
    message,
    stats: {
      total_users: data.total_users,
      new_users_today: data.new_users_today,
      active_markets: data.active_markets,
      resolved_today: data.resolved_today,
      volume_today: data.volume_today,
      pending_deposits: data.pending_deposits,
      pending_withdrawals: data.pending_withdrawals
    }
  }
};

// Also save to database for historical tracking
return {
  json: {
    saveQuery: `
      INSERT INTO daily_reports (report_date, total_users, new_users, active_markets, resolved_markets, volume_24h, pending_deposits, pending_withdrawals, created_at)
      VALUES (CURRENT_DATE, ${$input.first().json.stats.total_users}, ${$input.first().json.stats.new_users_today}, ${$input.first().json.stats.active_markets}, ${$input.first().json.stats.resolved_today}, ${$input.first().json.stats.volume_today}, ${$input.first().json.stats.pending_deposits}, ${$input.first().json.stats.pending_withdrawals}, NOW())
      ON CONFLICT (report_date) DO UPDATE SET
        total_users = EXCLUDED.total_users,
        new_users = EXCLUDED.new_users,
        active_markets = EXCLUDED.active_markets,
        resolved_markets = EXCLUDED.resolved_markets,
        volume_24h = EXCLUDED.volume_24h,
        pending_deposits = EXCLUDED.pending_deposits,
        pending_withdrawals = EXCLUDED.pending_withdrawals
    `
  }
};

// Final result
return {
  json: {
    success: true,
    report_sent: true,
    timestamp: new Date().toISOString()
  }
};
